local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LBuildingSprite:LxNodeBase
local LBuildingSprite = LxClass("LBuildingSprite", LxNodeBase)

local BuildingClick = CS.BuildingClick
------------------------------------------------------------------

function LBuildingSprite:LBuildingSprite()
	self._spriteKey    = nil
	self._refId 	= nil
	self._spriteTrans	= nil
	self._effectList = {}
	self._bInstantObject = false
end

function LBuildingSprite:CreateSprite(trans, key, bodyData, bInstantObject)
	if CS.IsNullObject(trans) then return end

	self._bInstantObject = bInstantObject or false
	if bInstantObject then
		local newtrans = LxResUtil.NewObject(trans.gameObject)
		if newtrans then
			newtrans = newtrans.transform
			LxUnity.SetParentTrans(newtrans, trans.transform.parent)
			newtrans.localPosition = trans.transform.localPosition
		end
		if CS.IsNullObject(newtrans) then return end

		trans = newtrans
	end

	self._mainBody = bodyData

	self._spriteTrans = trans
	self._spriteKey = key

    local mainBodyData = self._mainBody.main
	local spritePath = mainBodyData.spritePath
	self:SetSprite(spritePath)

	local scale = mainBodyData.bodyScale
	self:SetScale(scale)

	local pos = mainBodyData.pos
	self:SetLocalPos(pos)

	local rotate = mainBodyData.rotate
	self:SetLocalRotation(rotate)

	local effData = mainBodyData.effData
	self:SetShowEff(effData)

	self:SetTransClick(mainBodyData.clickTrans, mainBodyData.clickFunc)
end

function LBuildingSprite:IsDpValid()
	return self._spriteTrans and CS.IsValidObject(self._spriteTrans)
end

function LBuildingSprite:SetScale(scale)
	if not (self:IsDpValid() and scale) then return end

	self._spriteTrans.localScale = Vector3(scale,scale,scale)
end

function LBuildingSprite:SetLocalPos(pos)
	if not (self:IsDpValid() and pos) then return end

	self._spriteTrans.localPosition = pos
end

function LBuildingSprite:SetLocalRotation(ZRotate)
	if not (self:IsDpValid() and ZRotate) then return end

	self._spriteTrans.localRotation = Quaternion.Euler(0,0, ZRotate)
end

function LBuildingSprite:SetSprite(spritePath)
	if not (self:IsDpValid() and LxUiHelper.IsImgPathValid(spritePath)) then return end

	local trans = self._spriteTrans
	self:SetSpriteRenderer(trans, spritePath, function()
		CS.ShowObject(trans, true)
	end)
end

function LBuildingSprite:SetShowEff(effData)
	local effectKey = effData.key
	local effectData = self._effectList[effectKey]
	local effect
	if effectData then
		effectData.effData = effData
		if effectData.isLoaded then
			self:OnEffectLoaded(effectKey)
		end
		effect = effectData.effect
	else
		effect = LDisplayEffect:New()
		effectData = {effect = effect, effData = effData}
		self._effectList[effectKey] = effectData

		local trans = effData.trans
        local transPath = effData.transPath
        if not CS.IsValidObject(trans) and not string.isempty(transPath) then
            trans = CS.FindTrans(self._spriteTrans, transPath)
        end

		if CS.IsValidObject(trans) then
			effect:CreateEffect(trans, effData.resName)
			effect:SetLoadedFunction(function()
				self:OnEffectLoaded(effectKey)
			end)
			effect:StartLoadEffect()
		end
	end

	return effect
end

function LBuildingSprite:OnEffectLoaded(effectKey)
	local effectData = self._effectList[effectKey]
	if not effectData then return end

	effectData.isLoaded = true
	local effect = effectData.effect
	local effData = effectData.effData
	local dpTrans = effect:GetDisplayTrans()
	if effData.renderLayer then
		effect:SetRenderLayer(effData.renderLayer)
	end

	CS.SetParentTrans(dpTrans,effData.trans)
	dpTrans.localPosition = effData.pos or Vector3.zero
	dpTrans.name = effData.resName
	local scale = effData.scale or 1
	effect:SetEffectScale(scale)

	local endFunc = effData.endFunc
	if endFunc then
		endFunc(effect)
	end
end

function LBuildingSprite:DestroyByKey(key)
	local effectData = self._effectList[key]
	self._effectList[key] = nil
	if not effectData then return end

	local effect = effectData.effect
	effect:Destroy()
end

function LBuildingSprite:GetEffByKey(key)
	if not self._effectList then return end
	
	return self._effectList[key]
end

function LBuildingSprite:GetEffectTransByKey(key)
	local effInfo = self:GetEffByKey(key)
	return effInfo and effInfo.effect
end

function LBuildingSprite:SetTransClick(tran, clickFunc)
	if not (self:IsDpValid() and clickFunc) then return end

	if not tran then
		tran = self._spriteTrans
	end

	local comp = BuildingClick.Get(tran.gameObject)
	if comp then
		comp.ClickDelegate = clickFunc
	end
end

function LBuildingSprite:ClearEffect()
	for k,v in pairs(self._effectList) do
		local effect = v.effect
		effect:Destroy()
	end

	self._effectList = {}
end

function LBuildingSprite:Destroy()
	if self._isDestroy then return end

	self:ClearEffect()

	if self._bInstantObject and self._spriteTrans then
		LxResUtil.DestroyObject(self._spriteTrans.gameObject)
		self._spriteTrans = nil
	end

	LxNodeBase.Dispose(self)

	self._isDestroy = true
end


------------------------------------------------------------------
return LBuildingSprite